import java.util.*;

class SORTracker {

    public SORTracker() {
        this.locations = new TreeMap<>();
    }

    private TreeMap<Integer, List<String>> locations;

    public void add(String name, int score) {
        locations.computeIfAbsent(score, k -> new ArrayList<>()).add(name);
    }

    public String get() {
        int count = 0;
        for (List<String> names : locations.values()) {
            count += names.size();
            if (count == locations.size()) {
                return names.get(names.size() - 1);
            }
        }
        return null;
    }
}
```

